180→const PROJECT_ROOT = path.resolve(__dirname, '..');
181→const SRC_DIR = path.resolve(PROJECT_ROOT, 'src');
182→
183→const TILDE_MOCKS: Record<string, string> = {
184→  '~/store': path.resolve(__dirname, 'mocks/store.ts'),
185→  '~/redux/store/storage': path.resolve(__dirname, 'mocks/redux-store-storage.ts'),
186→};
187→
188→function tildeResolverPlugin(): PluginOption {
189→  return {
190→    name: 'storybook:tilde-resolver',
191→    enforce: 'pre',
192→    resolveId(source, importer) {
193→      if (!source.startsWith('~/') || !importer) return;
194→      if (importer.includes('node_modules')) return;
195→
196→      const mock = TILDE_MOCKS[source];
197→      if (mock) return mock;
198→
199→      return path.resolve(SRC_DIR, source.slice(2));
200→    },
201→  };
202→}
203→
204→const config: StorybookConfig = {
205→  stories: ['../src/**/*.stories.@(ts|tsx)'],
206→
207→  staticDirs: [
208→    // Ubuntu fonts from design system (Ubuntu-*.ttf)
209→    {
210→      from: '../node_modules/@semparar/design-system-app/src/assets/fonts',
211→      to: '/fonts',
212→    },
213→    // Icon fonts (IconsSemParar, icomoon) + other local fonts — overrides DS on name collision
214→    {
215→      from: '../src/assets/fonts',
216→      to: '/fonts',
217→    },
218→  ],
219→
220→  framework: {
221→    name: '@storybook/react-native-web-vite',
222→    options: {
223→      modulesToTranspile: [
224→        'react-native',
225→        'react-native-reanimated',
226→        'react-native-safe-area-context',
227→        'react-native-gesture-handler',
228→        'react-native-icomoon',
229→        'react-native-flip-card',
230→        'react-native-linear-gradient',
231→        'react-native-status-bar-height',
232→        'react-native-svg',
233→        'react-native-svg-charts',
234→        '@semparar/design-system-app',
235→      ],
236→    },
237→  },
238→
239→  addons: [
240→    '@storybook/addon-essentials',
241→    path.resolve(__dirname, 'addons/json-editor/register.tsx'),
242→  ],
243→
244→  viteFinal: async config => {
245→    config.plugins = config.plugins || [];
246→    config.plugins.push(tildeResolverPlugin());
247→    config.plugins.push(dtsStubPlugin());
248→    config.plugins.push(circularFixPlugin());
249→    config.plugins.push(jsxInJsPlugin());
250→    config.plugins.push(cjsToEsmPlugin());
251→
252→    config.optimizeDeps = config.optimizeDeps || {};
253→    config.optimizeDeps.include = [
254→      ...(config.optimizeDeps.include || []),
255→      'styled-components',
256→      'styled-components/native',
257→      'card-validator',
258→      'credit-card-type',
259→      'lodash',
260→      'xdate',
261→      'invariant',
262→      'fbjs',
263→      'hoist-non-react-statics',
264→      'prop-types',
265→      'object-assign',
266→      'shallowequal',
267→      'moment',
268→    ];
269→
270→    config.resolve = config.resolve || {};
271→    config.resolve.alias = {
272→      ...(config.resolve.alias || {}),
273→      // Native module mocks (no ~/ aliases here — handled by tildeResolverPlugin)
274→      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
275→      'react-native-linear-gradient': path.resolve(__dirname, 'mocks/react-native-linear-gradient.tsx'),
276→      'react-native-modalize': path.resolve(__dirname, 'mocks/react-native-modalize.tsx'),
277→      'react-native-skeleton-placeholder': path.resolve(__dirname, 'mocks/react-native-skeleton-placeholder.tsx'),
278→      '@react-native-community/slider': path.resolve(__dirname, 'mocks/react-native-community-slider.tsx'),
279→      'lottie-react-native': path.resolve(__dirname, 'mocks/lottie-react-native.tsx'),
280→      'react-native-video': path.resolve(__dirname, 'mocks/react-native-video.tsx'),
281→      '@react-native/assets-registry/registry': path.resolve(__dirname, 'mocks/react-native-assets-registry.tsx'),
282→      'deprecated-react-native-prop-types': path.resolve(__dirname, 'mocks/deprecated-react-native-prop-types.tsx'),
283→    };
284→    return config;
285→  },
286→};
287→
288→export default config;
